class Solution:
    def sortByReflection(self, nums):
        def reflect(x):
            bits = []
            while x > 0:
                bits.append(x & 1)
                x >>= 1
            val = 0
            for b in bits:
                val = (val << 1) | b
            return val

        return sorted(nums, key=lambda x: (reflect(x), x))

