var sortByReflection = function(nums) {
    function reflect(x) {
        const s = x.toString(2);
        return parseInt(s.split('').reverse().join(''), 2);
    }
    return nums.slice().sort((a, b) => {
        const ra = reflect(a), rb = reflect(b);
        if (ra !== rb) return ra - rb;
        return a - b;
    });
};
